/**
 * Re-export of the OpenAPI-generated types.
 *
 * The source file is `api.ts` in this directory, generated by
 * `pnpm run generate-types` from `Brain_API_Specification.yaml`.
 * Regenerate after every spec change. Commit the regenerated file
 * (Phase 2 plan item: "Commit the generated file; do not gitignore it").
 *
 * The SDK re-exports `paths`, `components`, and `operations` so namespace
 * modules can build typed wrappers without importing the giant `api.ts`
 * file directly.
 *
 * @packageDocumentation
 */

export type { components, operations, paths } from "./api.js";
